package com.example.knowledgecollector.web.security;
import org.springframework.stereotype.Service;import java.time.*;import java.util.concurrent.ConcurrentHashMap;
@Service public class LoginAttemptService {private record Attempt(int count,Instant blockedUntil){}private final ConcurrentHashMap<String,Attempt> attempts=new ConcurrentHashMap<>();public boolean blocked(String key){Attempt a=attempts.get(key(key));if(a==null)return false;if(a.blockedUntil()!=null&&a.blockedUntil().isAfter(Instant.now()))return true;if(a.blockedUntil()!=null)attempts.remove(key(key));return false;}public void failure(String key){attempts.compute(key(key),(k,a)->{int n=a==null?1:a.count()+1;return new Attempt(n,n>=5?Instant.now().plus(Duration.ofMinutes(10)):null);});}public void success(String key){attempts.remove(key(key));}private static String key(String s){return s==null?"":s.trim().toLowerCase();}}
